}

.orb-container {
  position: relative;
  width: 210px;
  height: 210px;
  margin: 0 auto 24px;
}

.orb-glow {
  position: absolute;
  inset: -40px;
  background: radial-gradient(circle, rgba(0,245,255,0.25) 0%, transparent 70%);
  border-radius: 50%;
  animation: glow-rotate 25s linear infinite;
}

.orb-ring {
  position: absolute;
  inset: 0;
  border-radius: 50%;
